def task_changes_materially_significant(changes: list[TaskChange]) -> bool:
    __list = changes
    if __list == []:
        return False
    t = __list[0]
    l = __list[1:]
    return True


def batched_rescope_materially_significant(
    snapshot_order: list[int],
    current_order: list[int],
    rows: dict[int, TaskRow],
    releases: list[RescopeRelease],
) -> bool:
    __pair = apply_batched_rescope(snapshot_order, current_order, rows, releases)
    l = __pair[0]
    rows_after = __pair[1]
    changes = compute_task_changes(
        snapshot_order,
        rows,
        rows_after,
    )
    return task_changes_materially_significant(changes)


def remove_from_order(
    task: int,
    order: list[int],
) -> list[int]:
    __list = order
    if __list == []:
        return []
    t = __list[0]
    rest = __list[1:]
    rest_ = remove_from_order(task, rest)
    if t == task:
        return rest_
    return [t] + rest_


def cleanup_aborted_task(
    task: int,
    lease: ExecutionLease | None,
    order: list[int],
    rows: dict[int, TaskRow],
) -> tuple[tuple[ExecutionLease | None, list[int]], dict[int, TaskRow]]:
    lease_ = clear_matching_lease(task, lease)
    order_ = remove_from_order(task, order)
    rows_ = _rocq_map_remove(
        _rocq_positive_key(task),
        rows,
    )
    return (
        (
            lease_,
            order_,
        ),
        rows_,
    )


def task_still_pending(
    task: int,
    rows: dict[int, TaskRow],
) -> bool:
    __option = rows.get(_rocq_positive_key(task))
    if __option is None:
        return False
    row = __option
    return isinstance(row.status, StatusPending)
